#!/usr/bin/env python3
"""
MadModem UI translation dictionary maintenance helper.

The application uses a light INI based runtime dictionary.  This script harvests:
  * explicit uiText("key", "English fallback") calls from C++/headers;
  * visible strings from Qt Designer .ui files.
It then refreshes translations/ui_*.ini and guarantees that each language has the
same key set.  The non-English dictionaries use curated exact translations for
common MadModem UI text plus conservative technical-term preservation.
"""
from __future__ import annotations

import ast
import re
import sys
import xml.etree.ElementTree as ET
from pathlib import Path
from collections import OrderedDict

ROOT = Path(__file__).resolve().parents[1]
TRANS_DIR = ROOT / "translations"
LANGS = ["en", "it", "fr", "de", "no", "cs"]

# ---------------------------------------------------------------------------
# Key generation matching MainWindow::uiTextFromSource().
# ---------------------------------------------------------------------------
def norm_key(source: str) -> str:
    normalized = []
    last_us = False
    for ch in source:
        if ch.isalnum():
            normalized.append(ch.lower())
            last_us = False
        else:
            if not last_us:
                normalized.append("_")
                last_us = True
    out = "".join(normalized).strip("_") or "empty"
    return out[:90]


def unescape_cpp(s: str) -> str:
    try:
        return ast.literal_eval('"' + s.replace('"', r'\"') + '"')
    except Exception:
        return s


def read_ini(path: Path) -> OrderedDict[str, str]:
    d: OrderedDict[str, str] = OrderedDict()
    if not path.exists():
        return d
    for raw in path.read_text(encoding="utf-8", errors="replace").splitlines():
        line = raw.strip()
        if not line or line.startswith("#") or line.startswith("[") or "=" not in line:
            continue
        k, v = line.split("=", 1)
        d[k.strip()] = v.strip().replace("\\n", "\n")
    return d


def write_ini(path: Path, lang: str, data: OrderedDict[str, str]) -> None:
    def esc(v: str) -> str:
        return v.replace("\n", "\\n")
    with path.open("w", encoding="utf-8", newline="\n") as f:
        f.write(f"# MadModem UI dictionary {lang}\n")
        f.write("# Generated by tools/update_ui_translations.py. Edit the exact phrase maps there.\n")
        for k, v in data.items():
            f.write(f"{k}={esc(v)}\n")


def harvest_keys() -> OrderedDict[str, str]:
    out: OrderedDict[str, str] = OrderedDict()

    ui_pat = re.compile(r'uiText\s*\(\s*"([^"]+)"\s*,\s*"((?:\\.|[^"])*)"', re.S)
    for p in sorted(list(ROOT.rglob("*.cpp")) + list(ROOT.rglob("*.h"))):
        if "/build-" in str(p) or "/third_party/" in str(p):
            continue
        text = p.read_text(encoding="utf-8", errors="replace")
        for m in ui_pat.finditer(text):
            key = m.group(1)
            fallback = unescape_cpp(m.group(2))
            if key == "key" and fallback == "fallback":
                continue
            out[key] = fallback

        # Dialog-local translators use either L("English source") or
        # L("stable_key", "English fallback").  Harvest both forms.  The
        # two-argument form must be harvested by its real stable key; otherwise
        # generated dictionaries show marker text such as scheduler_dialog_title.
        two_arg_l = re.compile(
            r'\bL\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"\s*\)?\s*,\s*'
            r'(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            re.S,
        )
        two_arg_spans = []
        for m in two_arg_l.finditer(text):
            key = unescape_cpp(m.group(1)).strip()
            fallback = unescape_cpp(m.group(2)).strip()
            two_arg_spans.append((m.start(), m.end()))
            if key and fallback:
                out.setdefault(key, fallback)

        def inside_two_arg_l(pos: int) -> bool:
            return any(a <= pos < b for a, b in two_arg_spans)

        # Single-argument L("English source") and runtime dictionary calls
        # resolve through MainWindow::uiTextFromSource()/MadModemI18n.  Skip
        # marker-like one-word keys to avoid polluting dictionaries with
        # internal ids.
        local_text_call_patterns = [
            r'\bL\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'\bL18n\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'\bP18n\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'\bMadModemI18n::text\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'(?<![A-Za-z0-9_:])T\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'\bMadModemI18n::placeholder\s*\(\s*(?:QStringLiteral\s*\(\s*)?"((?:\\.|[^"])*)"',
            r'(?<![A-Za-z0-9_:])tr\s*\(\s*"((?:\\.|[^"])*)"',
            r'\bQObject::tr\s*\(\s*"((?:\\.|[^"])*)"',
        ]
        for call_pat in local_text_call_patterns:
            for m in re.finditer(call_pat, text, re.S):
                if call_pat.startswith(r'\bL') and inside_two_arg_l(m.start()):
                    continue
                source = unescape_cpp(m.group(1)).strip()
                if not source:
                    continue
                if re.fullmatch(r'[a-z0-9_]+', source) and '_' in source:
                    continue
                if call_pat.startswith(r'\bMadModemI18n::placeholder') or call_pat.startswith(r'\bP18n'):
                    out.setdefault("placeholder." + norm_key(source), source)
                else:
                    out.setdefault("text." + norm_key(source), source)

    # Selected visible/runtime C++ strings.  This is intentionally not a generic
    # string-literal scraper: it only harvests strings passed to common UI/log
    # APIs where the user can see the text.  File names, object names, settings
    # keys and protocol constants remain excluded.
    visible_patterns = [
        (re.compile(r'appendLog\s*\(\s*"((?:\\.|[^"])*)"', re.S), "log"),
        (re.compile(r'appendLog\s*\(\s*QString\s*\(\s*"((?:\\.|[^"])*)"', re.S), "log"),
        (re.compile(r'appendLog\s*\(\s*QStringLiteral\s*\(\s*"((?:\\.|[^"])*)"', re.S), "log"),
        (re.compile(r'QMessageBox::(?:information|warning|critical|question)\s*\([^;]*?,\s*(?:QStringLiteral\s*\()?"((?:\\.|[^"])*)"\)?\s*,\s*(?:QStringLiteral\s*\()?"((?:\\.|[^"])*)"', re.S), "textpair"),
        (re.compile(r'new\s+(?:QLabel|QPushButton|QCheckBox|QGroupBox|QAction)\s*\(\s*(?:QStringLiteral\s*\()?"((?:\\.|[^"])*)"', re.S), "text"),
        (re.compile(r'(?:setWindowTitle|setText|setToolTip|setStatusTip|addItem|addTab|addAction|addMenu)\s*\(\s*(?:QStringLiteral\s*\()?"((?:\\.|[^"])*)"', re.S), "text"),
        (re.compile(r'QStringList\s*\(\s*\)\s*<<\s*"((?:\\.|[^"])*)"', re.S), "text"),
        (re.compile(r'<<\s*"((?:\\.|[^"])*)"', re.S), "text"),
    ]

    def plausible_user_text(src: str) -> bool:
        if src in {"MadModem 0.5.0"}:
            return False
        if not src or len(src) > 180:
            return False
        if src.startswith(":/") or src.startswith("/") or src.startswith("../"):
            return False
        if re.fullmatch(r'[A-Za-z0-9_./:-]+', src) and ('_' in src or '/' in src or src.endswith(('.cpp', '.h', '.ui', '.png', '.wav', '.adi'))):
            return False
        if src in {"default", "none", "cat_hamlib", "serial_rts", "serial_dtr", "mshv"}:
            return False
        return any(ch.isalpha() for ch in src)

    for p in sorted(list(ROOT.rglob("*.cpp")) + list(ROOT.rglob("*.h"))):
        ps = str(p)
        if "/build-" in ps or "/third_party/" in ps:
            continue
        text = p.read_text(encoding="utf-8", errors="replace")
        for pat, kind in visible_patterns:
            for m in pat.finditer(text):
                if kind == "textpair":
                    values = [unescape_cpp(m.group(1)), unescape_cpp(m.group(2))]
                    prefixes = ["text", "text"]
                else:
                    values = [unescape_cpp(m.group(1))]
                    prefixes = [kind]
                for value, prefix in zip(values, prefixes):
                    value = value.strip()
                    if plausible_user_text(value):
                        out.setdefault(prefix + "." + norm_key(value), value)

    # Explicit runtime keys which are not convenient to harvest from concatenated
    # rich-text literals but are still shown to the user.
    out.setdefault("help.autoqso_flow_html", (
        "<h2>MM Flow editor</h2>"
        "<p>This editor is becoming the visual programming layer for MadModem. "
        "Today it stores and validates the flow graph; live PTT/audio/CAT safety still remains in the scheduler.</p>"
        "<h3>Basic editing</h3>"
        "<ul>"
        "<li><b>Create a block:</b> press one of the + buttons, choose the type, title and note.</li>"
        "<li><b>Create an arrow:</b> select two blocks, press <b>Connect arrow</b>, choose the output port if needed.</li>"
        "<li><b>Delete an arrow:</b> click the arrow line and press <b>Delete arrows</b> or the Delete key.</li>"
        "<li><b>Delete a block:</b> select the block and press Delete. Connected arrows are removed too.</li>"
        "<li><b>Edit:</b> select exactly one block and press <b>Edit selected</b>. Shortcuts: Delete, Ctrl+E, Ctrl+L, Ctrl+H.</li>"
        "</ul>"
        "<h3>Programming blocks</h3>"
        "<ul>"
        "<li><b>Variable:</b> set/copy/increment/clear/list/map values.</li>"
        "<li><b>Compare:</b> compare variables, constants, decoded calls, bands, modes and regex matches.</li>"
        "<li><b>Loop:</b> iterate over decodes, candidates, log rows or bounded counters. Use next/done or loop/exit ports.</li>"
        "<li><b>I/O:</b> keyboard input, popup message/question, status message, log message, table output.</li>"
        "<li><b>Timer:</b> FT slot wait, decode-window wait, retry delay, interval, watchdog, UTC time trigger.</li>"
        "<li><b>Math:</b> arithmetic plus radio helpers such as locator distance/bearing.</li>"
        "</ul>"
        "<h3>Safety model</h3>"
        "<p>Flows may request abstract app actions. Dangerous operations such as TX, PTT, audio start, CAT QSY, file writes and scheduler operations must pass through MadModem's runtime guards.</p>"
    ))

    # Visible strings from Qt Designer forms.  These are translated through
    # MainWindow::translateObjectTree() using text.<normalized-source> keys.
    for ui in sorted(ROOT.rglob("*.ui")):
        try:
            tree = ET.parse(ui)
        except ET.ParseError:
            continue
        for node in tree.iter("string"):
            source = "".join(node.itertext()).strip()
            if not source:
                continue
            out.setdefault("text." + norm_key(source), source)
            out.setdefault("placeholder." + norm_key(source), source)

    return out

