def main() -> int:
    canonical = harvest_keys()
    TRANS_DIR.mkdir(exist_ok=True)

    # Keep stable-ish ordering: explicit action/menu keys first if present,
    # otherwise insertion order from existing en + harvested additions.
    for lang in LANGS:
        existing = read_ini(TRANS_DIR / f"ui_{lang}.ini")
        data: OrderedDict[str, str] = OrderedDict()
        for k, english in canonical.items():
            exact = KEY_EXACT.get(lang, {}).get(k)
            if exact is not None:
                data[k] = exact
            elif k in existing and existing[k].strip():
                # Preserve manually curated translations, especially the
                # ADIFMaster-style logbook strings added after harvesting.
                data[k] = existing[k]
            else:
                data[k] = translate_value(lang, english)
        write_ini(TRANS_DIR / f"ui_{lang}.ini", lang, data)
        print(f"{lang}: {len(data)} keys")
    return 0

if __name__ == "__main__":
    sys.exit(main())
